getDocuments.script:
(async () => {
  const base = 'https://www.blau.de/scs/bff/scs-207-customer-master-data-bff/customer-master-data/v1';
  const r = await fetch(base + '/onload/multiple/invoiceContent', { credentials: 'include' });
  const j = await r.json();
  const bill = j.billingAccountList[0];
  return {
    billingAccountId: bill.billAccountNumber,
    msisdn: bill.contractDetails[0].msisdn
  };
})()

(async () => {
  const base = 'https://www.blau.de/scs/bff/scs-207-customer-master-data-bff/customer-master-data/v1';
  const acct = '{{account.billingAccountId}}';
  const msisdn = '{{account.msisdn}}';
  const r = await fetch(
    base + '/onload/invoiceContent?subscribeType=prepaid&billingAccountId=' + acct + '&msisdn=' + msisdn + '&documentType=fisinvoice',
    { credentials: 'include' }
  );
  const j = await r.json();
  const invoices = (j.monthlyInvoices || []).concat(j.oldMonthlyInvoices || []);
  return invoices.map(inv => {
    const parts = inv.billDate.split('.');
    const isoDate = parts[2] + '-' + parts[1] + '-' + parts[0];
    return {
      id: inv.billId,
      date: isoDate,
      total: inv.billAmount
    };
  });
})()

forEach.script:
(async () => {
  const base = 'https://www.blau.de/scs/bff/scs-207-customer-master-data-bff/customer-master-data/v1';
  const r = await fetch(
    base + '/downloadDocument/PRINTSHOP:{{invoice.id}}',
    { credentials: 'include' }
  );
  const j = await r.json();
  if (j.attachment && j.attachment[0] && j.attachment[0].content) {
    return j.attachment[0].content;
  }
  throw new Error('No PDF attachment in response');
})()
